allow:
Bash(./vendor/bin/sail artisan tinker --execute="
use App\\Models\\{User, Company, Question, DailyLog, Analysis, SystemSetting};

echo 'Company count: ' . Company::count\(\) . PHP_EOL;
echo 'User count: ' . User::count\(\) . PHP_EOL;
echo 'Question count: ' . Question::count\(\) . PHP_EOL;

\\$admin = User::where\('is_admin', true\)->first\(\);
echo 'Admin: ' . \\$admin->name . ' / is_admin=' . \(\\$admin->is_admin ? 'true' : 'false'\) . PHP_EOL;
echo 'Admin company: ' . \\$admin->company->name . PHP_EOL;

\\$sub = User::where\('email', 'subordinate@example.com'\)->first\(\);
echo 'Subordinate: ' . \\$sub->name . PHP_EOL;

echo 'SystemSetting master date: ' . SystemSetting::getMasterDate\(\)->toDateTimeString\(\) . PHP_EOL;

echo 'Questions:' . PHP_EOL;
Question::active\(\)->get\(\)->each\(fn\(\\$q\) => print\('  - ' . \\$q->content . PHP_EOL\)\);
" 2>&1)
